 const bcrypt = require('bcrypt')
 const jwt = require('jsonwebtoken')
+const attempts = new Map()

+function rateLimit(ip) {
+  const now = Date.now()
+  const hits = (attempts.get(ip) || []).filter((t) => now - t < 60000)
+  hits.push(now)
+  attempts.set(ip, hits)
+  return hits.length <= 5
+}
